function solve(n: number, edges: number[][]): number {
    // Build adjacency list
    const adj: Map<number, { to: number; start: number; end: number }[]> = new Map();
    for (const [u, v, s, e] of edges) {
        if (!adj.has(u)) {
            adj.set(u, []);
        }
        adj.get(u)!.push({ to: v, start: s, end: e });
    }

    // Dijkstra's algorithm with priority queue
    const pq: [number, number][] = [[0, 0]]; // [time, node]
    const dist: Map<number, number> = new Map();
    dist.set(0, 0);

    while (pq.length > 0) {
        // Sort by time
        pq.sort((a, b) => a[0] - b[0]);
        const [currentTime, u] = pq.shift()!;

        // If we have already found a better time for this node, skip
        if (dist.has(u) && dist.get(u)! < currentTime) {
            continue;
        }

        // If we reached the destination
        if (u === n - 1) {
            return currentTime;
        }

        // Try to take each edge from u
        if (adj.has(u)) {
            for (const { to, start, end } of adj.get(u)!) {
                // Check if the edge is available at currentTime
                if (start <= currentTime && currentTime <= end) {
                    // We can take this edge, move to 'to' at currentTime + 1
                    const newTime = currentTime + 1;
                    if (!dist.has(to) || newTime < dist.get(to)!) {
                        dist.set(to, newTime);
                        pq.push([newTime, to]);
                    }
                }
            }
        }

        // Also consider staying at the current node (time increases by 1)
        const newTimeStay = currentTime + 1;
        if (!dist.has(u) || newTimeStay < dist.get(u)!) {
            dist.set(u, newTimeStay);
            pq.push([newTimeStay, u]);
        }
    }

    // If we couldn't reach the destination
    return -1;
}

